import React, { useEffect, useMemo, useState } from "react"
import { auth, AuthTokenPayload } from "../../../auth/auth";


type OutputValue = unknown

function Card(props: { title: string; children: React.ReactNode }) {
  return (
    <div
      style={{
        background: "#111827",
        border: "1px solid #1f2937",
        borderRadius: 16,
        padding: 20,
        boxShadow: "0 10px 30px rgba(0,0,0,0.2)"
      }}
    >
      <h2
        style={{
          margin: "0 0 16px",
          fontSize: 18,
          fontWeight: 700,
          color: "#f9fafb"
        }}
      >
        {props.title}
      </h2>
      {props.children}
    </div>
  )
}

function Field(props: {
  label: string
  value: string
  onChange: (value: string) => void
  type?: string
  placeholder?: string
}) {
  return (
    <label style={{ display: "block", marginBottom: 12 }}>
      <div
        style={{
          marginBottom: 6,
          fontSize: 13,
          color: "#9ca3af",
          fontWeight: 600
        }}
      >
        {props.label}
      </div>
      <input
        type={props.type || "text"}
        value={props.value}
        placeholder={props.placeholder}
        onChange={(e) => props.onChange(e.target.value)}
        style={{
          width: "100%",
          boxSizing: "border-box",
          padding: "12px 14px",
          borderRadius: 12,
          border: "1px solid #374151",
          background: "#0b1220",
          color: "#f9fafb",
          outline: "none"
        }}
      />
    </label>
  )
}

function Btn(props: {
  text: string
  onClick: () => void | Promise<void>
  tone?: "primary" | "secondary" | "danger"
}) {
  const bg =
    props.tone === "danger"
      ? "#991b1b"
      : props.tone === "secondary"
      ? "#1f2937"
      : "#2563eb"

  const border =
    props.tone === "danger"
      ? "#b91c1c"
      : props.tone === "secondary"
      ? "#374151"
      : "#3b82f6"

  return (
    <button
      onClick={() => void props.onClick()}
      style={{
        padding: "10px 14px",
        borderRadius: 12,
        border: `1px solid ${border}`,
        background: bg,
        color: "#fff",
        fontWeight: 700,
        cursor: "pointer"
      }}
    >
      {props.text}
    </button>
  )
}

export default function AuthTestPage() {
  const [username, setUsername] = useState("admin")
  const [password, setPassword] = useState("admin123")
  const [createRole, setCreateRole] = useState("user")
  const [targetUser, setTargetUser] = useState("")
  const [adminEmail, setAdminEmail] = useState("")
  const [output, setOutput] = useState<OutputValue>(null)
  const [error, setError] = useState<string>("")
  const [session, setSession] = useState<AuthTokenPayload | null>(null)

  const status = useMemo(() => {
    if (!session) return "Signed out"
    return `Signed in as ${session.sub} (${session.role})`
  }, [session])

  function refreshSession() {
    setSession(auth.getSession())
  }

  function setResult(value: OutputValue) {
    setError("")
    setOutput(value)
  }

  function setFailure(message: string) {
    setError(message)
  }

  async function run(action: () => Promise<any> | any) {
    try {
      const result = await action()
      if (typeof result !== "undefined") setResult(result)
      refreshSession()
    } catch (err: any) {
      setFailure(err?.message || "request failed")
      refreshSession()
    }
  }

  useEffect(() => {
    refreshSession()
  }, [])

  return (
    <div
      style={{
        minHeight: "100vh",
        background:
          "radial-gradient(circle at top, #1f2937 0%, #0b1020 45%, #050816 100%)",
        color: "#e5e7eb",
        padding: 32,
        fontFamily:
          'Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif'
      }}
    >
      <div style={{ maxWidth: 1200, margin: "0 auto" }}>
        <div style={{ marginBottom: 24 }}>
          <h1
            style={{
              margin: 0,
              fontSize: 34,
              lineHeight: 1.1,
              color: "#f9fafb"
            }}
          >
            Cloudflare Auth Test Console
          </h1>
          <p style={{ margin: "10px 0 0", color: "#9ca3af", fontSize: 15 }}>
            A less embarrassing test UI for your auth API.
          </p>
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))",
            gap: 18
          }}
        >
          <Card title="Session">
            <div
              style={{
                padding: 14,
                borderRadius: 12,
                background: "#0b1220",
                border: "1px solid #243041",
                marginBottom: 16
              }}
            >
              <div style={{ fontSize: 14, color: "#cbd5e1", fontWeight: 700 }}>
                {status}
              </div>
              <div style={{ fontSize: 13, color: "#94a3b8", marginTop: 8 }}>
                Current role: {auth.getRole() || "none"}
              </div>
            </div>

            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              <Btn text="Check Status" tone="secondary" onClick={() => run(() => auth.me())} />
              <Btn text="Decode Local Token" tone="secondary" onClick={() => run(() => auth.decodeToken())} />
              <Btn text="Sign Out" tone="danger" onClick={() => run(() => auth.logout())} />
            </div>
          </Card>

          <Card title="Sign In">
            <Field
              label="Username"
              value={username}
              onChange={setUsername}
              placeholder="admin"
            />
            <Field
              label="Password"
              type="password"
              value={password}
              onChange={setPassword}
              placeholder="••••••••"
            />

            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              <Btn text="Sign In" onClick={() => run(() => auth.login(username, password))} />
            </div>
          </Card>

          <Card title="Create User">
            <Field
              label="Username"
              value={username}
              onChange={setUsername}
              placeholder="new-user"
            />
            <Field
              label="Password"
              type="password"
              value={password}
              onChange={setPassword}
              placeholder="password"
            />
            <Field
              label="Role"
              value={createRole}
              onChange={setCreateRole}
              placeholder="user / editor / admin"
            />

            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              <Btn
                text="Create User"
                onClick={() =>
                  run(() => auth.createUser(username, password, createRole))
                }
              />
            </div>
          </Card>

          <Card title="Protected Data">
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              <Btn
                text="Get User Data"
                tone="secondary"
                onClick={() => run(() => auth.getProtectedUserData())}
              />
              <Btn
                text="Get Admin Data"
                onClick={() => run(() => auth.getProtectedAdminData())}
              />
            </div>
          </Card>

          <Card title="User Admin">
            <Field
              label="Target Username"
              value={targetUser}
              onChange={setTargetUser}
              placeholder="editor"
            />

            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              <Btn
                text="Revoke User"
                tone="danger"
                onClick={() => run(() => auth.revokeUser(targetUser))}
              />
              <Btn
                text="Unlock User"
                tone="secondary"
                onClick={() => run(() => auth.unlockUser(targetUser))}
              />
            </div>
          </Card>

          <Card title="Admin Contact">
            <Field
              label="Admin Email"
              value={adminEmail}
              onChange={setAdminEmail}
              placeholder="admin@example.com"
            />

            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              <Btn
                text="Set Admin Contact"
                onClick={() => run(() => auth.setAdminContact(adminEmail))}
              />
              <Btn
                text="Get Admin Contact"
                tone="secondary"
                onClick={() => run(() => auth.getAdminContact())}
              />
            </div>
          </Card>
        </div>

        <div
          style={{
            marginTop: 20,
            display: "grid",
            gridTemplateColumns: "1fr",
            gap: 18
          }}
        >
          <Card title="Raw Token">
            <pre
              style={{
                margin: 0,
                whiteSpace: "pre-wrap",
                wordBreak: "break-all",
                color: "#cbd5e1",
                background: "#0b1220",
                border: "1px solid #243041",
                padding: 14,
                borderRadius: 12
              }}
            >
              {auth.getToken() || "No token stored"}
            </pre>
          </Card>

          <Card title="Response">
            {error ? (
              <div
                style={{
                  marginBottom: 12,
                  background: "#3f1117",
                  border: "1px solid #7f1d1d",
                  color: "#fecaca",
                  padding: 12,
                  borderRadius: 12,
                  fontWeight: 700
                }}
              >
                {error}
              </div>
            ) : null}

            <pre
              style={{
                margin: 0,
                whiteSpace: "pre-wrap",
                wordBreak: "break-word",
                color: "#cbd5e1",
                background: "#0b1220",
                border: "1px solid #243041",
                padding: 14,
                borderRadius: 12,
                minHeight: 180
              }}
            >
              {JSON.stringify(output, null, 2)}
            </pre>
          </Card>
        </div>
      </div>
    </div>
  )
}