const API = "https://auth.snowy-frost-b196.workers.dev"

export type AuthTokenPayload = {
  sub: string
  role: string
  meta?: Record<string, unknown>
  iat: number
  exp: number
}

function isBrowser(): boolean {
  return typeof window !== "undefined" && typeof window.localStorage !== "undefined"
}

function getStoredToken(): string | null {
  if (!isBrowser()) return null
  return window.localStorage.getItem("auth_token")
}

function setStoredToken(token: string): void {
  if (!isBrowser()) return
  window.localStorage.setItem("auth_token", token)
}

function clearStoredToken(): void {
  if (!isBrowser()) return
  window.localStorage.removeItem("auth_token")
}

function safeJsonParse<T>(value: string): T | null {
  try {
    return JSON.parse(value) as T
  } catch {
    return null
  }
}

function decodeBase64Url(value: string): string {
  const normalized = value.replace(/-/g, "+").replace(/_/g, "/")
  const padded = normalized + "=".repeat((4 - (normalized.length % 4)) % 4)

  if (typeof window !== "undefined" && typeof window.atob === "function") {
    return window.atob(padded)
  }

  if (typeof atob === "function") {
    return atob(padded)
  }

  throw new Error("base64 decoding is not available in this environment")
}

function decodeTokenInternal(token: string): AuthTokenPayload | null {
  try {
    const parts = token.split(".")
    if (parts.length < 2) return null
    const payloadRaw = decodeBase64Url(parts[1])
    return safeJsonParse<AuthTokenPayload>(payloadRaw)
  } catch {
    return null
  }
}

async function parseResponse(res: Response): Promise<any> {
  const text = await res.text()

  if (!text) return null

  try {
    return JSON.parse(text)
  } catch {
    return text
  }
}

export const auth = {
  apiBase: API,

  getToken(): string | null {
    return getStoredToken()
  },

  setToken(token: string): void {
    setStoredToken(token)
  },

  clearToken(): void {
    clearStoredToken()
  },

  decodeToken(token?: string | null): AuthTokenPayload | null {
    const t = token ?? getStoredToken()
    if (!t) return null
    return decodeTokenInternal(t)
  },

  isLoggedIn(): boolean {
    const session = this.getSession()
    if (!session) return false
    return session.exp > Date.now()
  },

  getSession(): AuthTokenPayload | null {
    const token = getStoredToken()
    if (!token) return null

    const payload = decodeTokenInternal(token)
    if (!payload) {
      clearStoredToken()
      return null
    }

    if (payload.exp <= Date.now()) {
      clearStoredToken()
      return null
    }

    return payload
  },

  getRole(): string | null {
    return this.getSession()?.role ?? null
  },

  getUserId(): string | null {
    return this.getSession()?.sub ?? null
  },

  async login(username: string, password: string): Promise<AuthTokenPayload> {
    const res = await fetch(API + "/auth/login", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ username, password })
    })

    const data = await parseResponse(res)

    if (!res.ok || !data?.token) {
      throw new Error(data?.error || "login failed")
    }

    setStoredToken(data.token)

    const payload = decodeTokenInternal(data.token)
    if (!payload) {
      clearStoredToken()
      throw new Error("invalid token returned by server")
    }

    return payload
  },

  logout(): void {
    clearStoredToken()
  },

  async me(): Promise<AuthTokenPayload> {
    return this.api("/auth/me")
  },

  async api(path: string, options: RequestInit = {}): Promise<any> {
    const token = getStoredToken()

    const headers: Record<string, string> = {
      ...(options.headers as Record<string, string> | undefined)
    }

    if (!(options.body instanceof FormData)) {
      headers["Content-Type"] = headers["Content-Type"] || "application/json"
    }

    if (token) {
      headers["Authorization"] = `Bearer ${token}`
    }

    const res = await fetch(API + path, {
      ...options,
      headers
    })

    const data = await parseResponse(res)

    if (res.status === 401) {
      clearStoredToken()
      throw new Error((data && data.error) || "unauthorized")
    }

    if (!res.ok) {
      throw new Error((data && data.error) || `request failed (${res.status})`)
    }

    return data
  },

  async createUser(username: string, password: string, role: string) {
    return this.api("/auth/createUser", {
      method: "POST",
      body: JSON.stringify({ username, password, role })
    })
  },

  async revokeUser(username: string) {
    return this.api("/auth/revokeUser", {
      method: "POST",
      body: JSON.stringify({ username })
    })
  },

  async unlockUser(username: string) {
    return this.api("/auth/unlockUser", {
      method: "POST",
      body: JSON.stringify({ username })
    })
  },

  async setAdminContact(email: string) {
    return this.api("/auth/setAdminContact", {
      method: "POST",
      body: JSON.stringify({ email })
    })
  },

  async getAdminContact() {
    return this.api("/auth/getAdminContact")
  },

  async getProtectedUserData() {
    return this.api("/user/data")
  },

  async getProtectedAdminData() {
    return this.api("/admin/data")
  }
}